import{_ as a,o as n,c as t,ag as s}from"./chunks/framework.aJXYWJub.js";const u=JSON.parse('{"title":"架构概览","description":"","frontmatter":{"generated":true},"headers":[],"relativePath":"reference/architecture.md","filePath":"reference/architecture.md","lastUpdated":1772068138000}'),o={name:"reference/architecture.md"};function r(d,e,i,c,l,p){return n(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="架构概览" tabindex="-1">架构概览 <a class="header-anchor" href="#架构概览" aria-label="Permalink to &quot;架构概览&quot;">​</a></h1><blockquote><p>基于 v0.2.2 (2026-02-24)</p></blockquote><h1 id="actant-v0-2-2-—-architecture-document" tabindex="-1">Actant v0.2.2 — Architecture Document <a class="header-anchor" href="#actant-v0-2-2-—-architecture-document" aria-label="Permalink to &quot;Actant v0.2.2 — Architecture Document&quot;">​</a></h1><blockquote><p><strong>Actant</strong> is &quot;Docker for AI Agents&quot; — a platform to build, manage, and compose AI agents with pluggable backends, declarative configuration, and a component ecosystem.</p></blockquote><h2 id="tech-stack" tabindex="-1">Tech Stack <a class="header-anchor" href="#tech-stack" aria-label="Permalink to &quot;Tech Stack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Technology</th></tr></thead><tbody><tr><td>Runtime</td><td>Node.js 20+ / TypeScript 5.7</td></tr><tr><td>Build</td><td>tsup (ESM) + pnpm workspaces</td></tr><tr><td>Validation</td><td>Zod</td></tr><tr><td>CLI</td><td>Commander.js</td></tr><tr><td>IPC</td><td>JSON-RPC 2.0 over Unix socket / Windows named pipe</td></tr><tr><td>Agent Protocol</td><td>ACP (Agent Client Protocol)</td></tr><tr><td>Testing</td><td>Vitest</td></tr><tr><td>Package Manager</td><td>pnpm 10</td></tr></tbody></table><h2 id="monorepo-structure" tabindex="-1">Monorepo Structure <a class="header-anchor" href="#monorepo-structure" aria-label="Permalink to &quot;Monorepo Structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-dark github-dark vp-code" tabindex="0"><code><span class="line"><span>packages/</span></span>
<span class="line"><span>├── shared/       @actant/shared      Types, logger, config helpers (foundation)</span></span>
<span class="line"><span>├── core/         @actant/core        Runtime engine (managers, builders, domain)</span></span>
<span class="line"><span>├── api/          @actant/api         Daemon, socket server, RPC handlers</span></span>
<span class="line"><span>├── cli/          @actant/cli         CLI frontend (commander-based)</span></span>
<span class="line"><span>├── acp/          @actant/acp         Agent Client Protocol adapter</span></span>
<span class="line"><span>├── pi/           @actant/pi          Pi — in-process lightweight agent backend</span></span>
<span class="line"><span>├── mcp-server/   @actant/mcp-server  MCP server integration</span></span>
<span class="line"><span>└── actant/       actant              Meta-package + global binary</span></span></code></pre></div><h3 id="package-dependency-graph" tabindex="-1">Package Dependency Graph <a class="header-anchor" href="#package-dependency-graph" aria-label="Permalink to &quot;Package Dependency Graph&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-dark github-dark vp-code" tabindex="0"><code><span class="line"><span>                    ┌──────────┐</span></span>
<span class="line"><span>                    │  actant  │  (meta-package)</span></span>
<span class="line"><span>                    └────┬─────┘</span></span>
<span class="line"><span>          ┌──────┬───────┼───────┬──────┬──────┐</span></span>
<span class="line"><span>          ▼      ▼       ▼       ▼      ▼      ▼</span></span>
<span class="line"><span>        cli    api     core    acp    pi    mcp-server</span></span>
<span class="line"><span>          │      │       │       │      │      │</span></span>
<span class="line"><span>          ├──────┤       │       ├──────┘      │</span></span>
<span class="line"><span>          │      ├───────┤       │             │</span></span>
<span class="line"><span>          │      │       │       ▼             │</span></span>
<span class="line"><span>          └──────┴───────┴──► shared ◄─────────┘</span></span></code></pre></div><h2 id="module-architecture" tabindex="-1">Module Architecture <a class="header-anchor" href="#module-architecture" aria-label="Permalink to &quot;Module Architecture&quot;">​</a></h2><h3 id="_1-actant-shared-—-foundation-types" tabindex="-1">1. <code>@actant/shared</code> — Foundation Types <a class="header-anchor" href="#_1-actant-shared-—-foundation-types" aria-label="Permalink to &quot;1. \`@actant/shared\` — Foundation Types&quot;">​</a></h3><p>Pure type definitions and shared utilities. No runtime logic.</p><ul><li><strong>Types</strong>: <code>AgentInstanceMeta</code>, <code>AgentTemplate</code>, <code>BackendDefinition</code>, <code>VersionedComponent</code>, <code>DomainContextConfig</code>, <code>SourceConfig</code>, <code>RPC method map</code></li><li><strong>Utilities</strong>: Logger (pino), IPC helpers, platform detection</li><li><strong>Error hierarchy</strong>: <code>ActantError</code> → <code>AgentNotFoundError</code>, <code>ConfigValidationError</code>, <code>ComponentReferenceError</code>, etc.</li></ul><h3 id="_2-actant-core-—-runtime-engine" tabindex="-1">2. <code>@actant/core</code> — Runtime Engine <a class="header-anchor" href="#_2-actant-core-—-runtime-engine" aria-label="Permalink to &quot;2. \`@actant/core\` — Runtime Engine&quot;">​</a></h3><p>The core logic layer containing all business rules.</p><h4 id="manager-src-manager" tabindex="-1">Manager (<code>src/manager/</code>) <a class="header-anchor" href="#manager-src-manager" aria-label="Permalink to &quot;Manager (\`src/manager/\`)&quot;">​</a></h4><ul><li><p><strong>AgentManager</strong> — The central orchestrator for agent lifecycle</p><ul><li>State machine: <code>created → starting → running → stopping → stopped</code></li><li>Launch modes: <code>direct</code>, <code>acp-background</code>, <code>acp-service</code>, <code>one-shot</code></li><li>Process ownership: <code>managed</code> (Actant spawns) or <code>external</code> (user spawns, Actant attaches)</li><li>Workspace policy: <code>persistent</code> or <code>ephemeral</code></li><li>Methods: <code>createAgent</code>, <code>startAgent</code>, <code>stopAgent</code>, <code>destroyAgent</code>, <code>runPrompt</code>, <code>streamPrompt</code>, <code>resolveAgent</code>, <code>openAgent</code>, <code>attachAgent</code>, <code>detachAgent</code></li></ul></li><li><p><strong>ProcessLauncher</strong> — Spawns backend processes</p></li><li><p><strong>LaunchModeHandler</strong> — Determines behavior on process exit per launch mode</p></li><li><p><strong>RestartTracker</strong> — Manages restart policies for <code>acp-service</code> mode</p></li><li><p><strong>ProcessWatcher</strong> — Monitors process health via PID polling</p></li></ul><h4 id="domain-src-domain" tabindex="-1">Domain (<code>src/domain/</code>) <a class="header-anchor" href="#domain-src-domain" aria-label="Permalink to &quot;Domain (\`src/domain/\`)&quot;">​</a></h4><p>All domain components are <code>VersionedComponent</code>s managed by <code>BaseComponentManager</code>:</p><table tabindex="0"><thead><tr><th>Manager</th><th>Component</th><th>Persistence Dir</th></tr></thead><tbody><tr><td><code>SkillManager</code></td><td><code>SkillDefinition</code></td><td><code>configs/skills/</code></td></tr><tr><td><code>PromptManager</code></td><td><code>PromptDefinition</code></td><td><code>configs/prompts/</code></td></tr><tr><td><code>McpConfigManager</code></td><td><code>McpServerDefinition</code></td><td><code>configs/mcp/</code></td></tr><tr><td><code>WorkflowManager</code></td><td><code>WorkflowDefinition</code></td><td><code>configs/workflows/</code></td></tr><tr><td><code>PluginManager</code></td><td><code>PluginDefinition</code></td><td><code>configs/plugins/</code></td></tr><tr><td><code>BackendManager</code></td><td><code>BackendDefinition</code></td><td><code>configs/backends/</code></td></tr></tbody></table><p><code>BaseComponentManager</code> provides: <code>register</code>, <code>unregister</code>, <code>get</code>, <code>has</code>, <code>list</code>, <code>add</code>, <code>update</code>, <code>remove</code>, <code>importFromFile</code>, <code>exportToFile</code>, <code>search</code>, <code>filter</code>, <code>loadFromDirectory</code>, <code>validate</code>.</p><p><code>BackendManager</code> adds: <code>registerAcpResolver</code>, <code>getAcpResolver</code>, <code>supportsMode</code>, <code>requireMode</code>, <code>checkAvailability</code>, <code>getInstallMethods</code>.</p><h4 id="backend-system-src-domain-backend-src-manager-launcher" tabindex="-1">Backend System (<code>src/domain/backend/</code> + <code>src/manager/launcher/</code>) <a class="header-anchor" href="#backend-system-src-domain-backend-src-manager-launcher" aria-label="Permalink to &quot;Backend System (\`src/domain/backend/\` + \`src/manager/launcher/\`)&quot;">​</a></h4><p>Backends are <code>VersionedComponent</code>s (JSON-serializable) with behavioral extensions:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-dark github-dark vp-code" tabindex="0"><code><span class="line"><span>BackendDefinition (data, serializable)</span></span>
<span class="line"><span>├── name, version, description, tags</span></span>
<span class="line"><span>├── supportedModes: [&quot;resolve&quot;, &quot;open&quot;, &quot;acp&quot;]</span></span>
<span class="line"><span>├── resolveCommand / openCommand / acpCommand (PlatformCommand)</span></span>
<span class="line"><span>├── openSpawnOptions (OpenSpawnOptions)</span></span>
<span class="line"><span>├── existenceCheck (BackendExistenceCheck)</span></span>
<span class="line"><span>└── install (BackendInstallMethod[])</span></span>
<span class="line"><span></span></span>
<span class="line"><span>BackendManager (behavior, non-serializable)</span></span>
<span class="line"><span>├── acpResolvers: Map&lt;string, AcpResolverFn&gt;</span></span>
<span class="line"><span>├── checkAvailability() — runs existenceCheck</span></span>
<span class="line"><span>└── getInstallMethods() — platform-filtered</span></span></code></pre></div><p>Built-in backends:</p><table tabindex="0"><thead><tr><th>Backend</th><th>Modes</th><th>Binary</th><th>Notes</th></tr></thead><tbody><tr><td><code>cursor</code></td><td>resolve, open</td><td><code>cursor.cmd</code> / <code>cursor</code></td><td>IDE; shell spawn</td></tr><tr><td><code>cursor-agent</code></td><td>resolve, open, acp</td><td><code>agent</code></td><td>TUI; cwd-based open</td></tr><tr><td><code>claude-code</code></td><td>resolve, open, acp</td><td><code>claude-agent-acp.cmd</code> / <code>claude</code></td><td>resolvePackage for ACP</td></tr><tr><td><code>pi</code></td><td>acp</td><td>in-process</td><td>ACP owns process</td></tr><tr><td><code>custom</code></td><td>resolve</td><td>user-defined</td><td>Fallback</td></tr></tbody></table><h4 id="source-system-src-source" tabindex="-1">Source System (<code>src/source/</code>) <a class="header-anchor" href="#source-system-src-source" aria-label="Permalink to &quot;Source System (\`src/source/\`)&quot;">​</a></h4><ul><li><strong>SourceManager</strong> — Manages external component repositories</li><li><strong>GitHubSource</strong> — Shallow clone from GitHub</li><li><strong>LocalSource</strong> — Reads from local directory</li><li><strong>Namespacing</strong>: Components from sources get <code>packageName@componentName</code> prefix</li><li><strong>Default source</strong>: <code>actant-hub</code> at <code>github.com/blackplume233/actant-hub.git</code></li></ul><p>Supports: skills, prompts, mcp, workflows, backends, presets, templates.</p><h4 id="builder-system-src-builder" tabindex="-1">Builder System (<code>src/builder/</code>) <a class="header-anchor" href="#builder-system-src-builder" aria-label="Permalink to &quot;Builder System (\`src/builder/\`)&quot;">​</a></h4><p>Materializes agent workspaces from domain context:</p><ul><li><strong>WorkspaceBuilder</strong> — Orchestrates context materialization</li><li><strong>CursorBuilder</strong> — <code>.cursor/</code> config files (rules, mcp.json, extensions.json)</li><li><strong>ClaudeCodeBuilder</strong> — <code>.claude/</code> config files (CLAUDE.md, settings.json)</li><li><strong>Handlers</strong>: <code>SkillsHandler</code>, <code>PromptsHandler</code>, <code>McpServersHandler</code>, <code>WorkflowHandler</code></li></ul><h4 id="template-system-src-template" tabindex="-1">Template System (<code>src/template/</code>) <a class="header-anchor" href="#template-system-src-template" aria-label="Permalink to &quot;Template System (\`src/template/\`)&quot;">​</a></h4><ul><li><strong>TemplateLoader</strong> — Loads from files, validates via Zod</li><li><strong>TemplateRegistry</strong> — In-memory registry</li><li><strong>TemplateFileWatcher</strong> — Hot-reload on file changes</li><li><strong>Validation</strong>: <code>AgentTemplateSchema</code> (Zod) validates all fields</li></ul><h4 id="initializer-system-src-initializer" tabindex="-1">Initializer System (<code>src/initializer/</code>) <a class="header-anchor" href="#initializer-system-src-initializer" aria-label="Permalink to &quot;Initializer System (\`src/initializer/\`)&quot;">​</a></h4><p>Creates agent instance directories via pipeline:</p><ul><li><strong>InitializationPipeline</strong> — Sequential steps</li><li>Steps: <code>MkdirStep</code>, <code>FileCopyStep</code>, <code>GitCloneStep</code>, <code>NpmInstallStep</code>, <code>ExecStep</code></li><li><strong>ContextMaterializer</strong> — Assembles domain components into workspace</li></ul><h4 id="scheduler-src-scheduler" tabindex="-1">Scheduler (<code>src/scheduler/</code>) <a class="header-anchor" href="#scheduler-src-scheduler" aria-label="Permalink to &quot;Scheduler (\`src/scheduler/\`)&quot;">​</a></h4><ul><li><strong>EmployeeScheduler</strong> — Manages heartbeat, cron, hook triggers</li><li><strong>TaskDispatcher</strong> — Priority queue, sequential execution</li><li><strong>ExecutionLog</strong> — Per-agent execution history</li><li>Configs: <code>HeartbeatConfig</code> (intervalMs), <code>CronConfig</code> (pattern), <code>HookConfig</code> (eventName)</li></ul><h4 id="provider-src-provider" tabindex="-1">Provider (<code>src/provider/</code>) <a class="header-anchor" href="#provider-src-provider" aria-label="Permalink to &quot;Provider (\`src/provider/\`)&quot;">​</a></h4><ul><li><strong>ModelProviderRegistry</strong> — Manages AI provider configs</li><li>Built-in: <code>anthropic</code>, <code>openai</code>, <code>gemini</code>, <code>openrouter</code></li></ul><h3 id="_3-actant-api-—-daemon-handlers" tabindex="-1">3. <code>@actant/api</code> — Daemon &amp; Handlers <a class="header-anchor" href="#_3-actant-api-—-daemon-handlers" aria-label="Permalink to &quot;3. \`@actant/api\` — Daemon &amp; Handlers&quot;">​</a></h3><h4 id="daemon-src-daemon" tabindex="-1">Daemon (<code>src/daemon/</code>) <a class="header-anchor" href="#daemon-src-daemon" aria-label="Permalink to &quot;Daemon (\`src/daemon/\`)&quot;">​</a></h4><ul><li><strong>Daemon</strong> — Long-running background service</li><li><strong>SocketServer</strong> — JSON-RPC 2.0 over Unix socket / Windows named pipe</li><li><strong>PidFile</strong> — Process lock via PID file</li><li><strong>AcpRelayServer</strong> — Routes ACP session updates to CLI clients</li></ul><h4 id="handlers-src-handlers" tabindex="-1">Handlers (<code>src/handlers/</code>) <a class="header-anchor" href="#handlers-src-handlers" aria-label="Permalink to &quot;Handlers (\`src/handlers/\`)&quot;">​</a></h4><p>62 RPC methods across 11 handler groups:</p><table tabindex="0"><thead><tr><th>Handler</th><th>Method Count</th><th>Key Methods</th></tr></thead><tbody><tr><td>template</td><td>5</td><td>list, get, load, unload, validate</td></tr><tr><td>agent</td><td>16</td><td>create, start, stop, destroy, status, list, resolve, open, attach, detach, run, prompt, adopt, dispatch, tasks, logs</td></tr><tr><td>session</td><td>5</td><td>create, prompt, cancel, close, list</td></tr><tr><td>domain (×5)</td><td>25</td><td>list, get, add, update, remove, import, export (per type)</td></tr><tr><td>source</td><td>5</td><td>list, add, remove, sync, validate</td></tr><tr><td>preset</td><td>3</td><td>list, show, apply</td></tr><tr><td>daemon</td><td>2</td><td>ping, shutdown</td></tr><tr><td>proxy</td><td>3</td><td>connect, disconnect, forward</td></tr><tr><td>schedule</td><td>1</td><td>list</td></tr></tbody></table><h4 id="appcontext-src-services" tabindex="-1">AppContext (<code>src/services/</code>) <a class="header-anchor" href="#appcontext-src-services" aria-label="Permalink to &quot;AppContext (\`src/services/\`)&quot;">​</a></h4><ul><li>Initializes all managers, registries, and services</li><li>Registers built-in backends, providers</li><li>Loads domain components from disk and sources</li><li>Registers Pi backend with ACP resolver</li></ul><h3 id="_4-actant-cli-—-command-line-interface" tabindex="-1">4. <code>@actant/cli</code> — Command-Line Interface <a class="header-anchor" href="#_4-actant-cli-—-command-line-interface" aria-label="Permalink to &quot;4. \`@actant/cli\` — Command-Line Interface&quot;">​</a></h3><p>68 subcommands organized into 15 command groups:</p><table tabindex="0"><thead><tr><th>Group</th><th>Commands</th><th>Description</th></tr></thead><tbody><tr><td>agent</td><td>17</td><td>Full lifecycle management</td></tr><tr><td>template</td><td>5</td><td>Template CRUD</td></tr><tr><td>skill</td><td>5</td><td>Skill CRUD</td></tr><tr><td>prompt</td><td>5</td><td>Prompt CRUD</td></tr><tr><td>mcp</td><td>5</td><td>MCP server config CRUD</td></tr><tr><td>workflow</td><td>5</td><td>Workflow CRUD</td></tr><tr><td>plugin</td><td>5</td><td>Plugin CRUD</td></tr><tr><td>source</td><td>5</td><td>Source management</td></tr><tr><td>preset</td><td>3</td><td>Preset management</td></tr><tr><td>schedule</td><td>1</td><td>Schedule listing</td></tr><tr><td>daemon</td><td>3</td><td>Daemon control</td></tr><tr><td>proxy</td><td>1</td><td>ACP proxy</td></tr><tr><td>setup</td><td>1</td><td>Interactive wizard</td></tr><tr><td>self-update</td><td>1</td><td>Auto-update</td></tr><tr><td>help</td><td>1</td><td>Help display</td></tr></tbody></table><ul><li><strong>RpcClient</strong> — Connects to daemon via socket, sends JSON-RPC requests</li><li><strong>Output formats</strong>: <code>table</code> (default), <code>json</code> via <code>-f</code> flag</li><li><strong>Error presentation</strong>: Colored RPC error codes with context</li></ul><h3 id="_5-actant-acp-—-agent-client-protocol" tabindex="-1">5. <code>@actant/acp</code> — Agent Client Protocol <a class="header-anchor" href="#_5-actant-acp-—-agent-client-protocol" aria-label="Permalink to &quot;5. \`@actant/acp\` — Agent Client Protocol&quot;">​</a></h3><ul><li><strong>AcpConnection</strong> — Manages lifecycle of one agent subprocess via ACP SDK</li><li><strong>AcpConnectionManager</strong> — Pool of connections by agent name</li><li><strong>AcpCommunicator</strong> — Implements <code>AgentCommunicator</code> over ACP</li><li><strong>AcpGateway</strong> — IDE ↔ Agent bridge (upstream <code>AgentSide</code> ↔ downstream <code>ClientSide</code>)</li><li><strong>ClientCallbackRouter</strong> — Routes permission requests, file operations, terminal ops</li><li><strong>LocalTerminalManager</strong> — Local terminal handling for headless mode</li></ul><h3 id="_6-actant-pi-—-lightweight-in-process-agent" tabindex="-1">6. <code>@actant/pi</code> — Lightweight In-Process Agent <a class="header-anchor" href="#_6-actant-pi-—-lightweight-in-process-agent" aria-label="Permalink to &quot;6. \`@actant/pi\` — Lightweight In-Process Agent&quot;">​</a></h3><ul><li><strong>PiBuilder</strong> — Workspace builder for Pi agents</li><li><strong>PiCommunicator</strong> — Direct LLM communication (Anthropic, OpenAI, etc.)</li><li><strong>ACP Bridge</strong> — <code>pi-acp-bridge</code> binary for ACP protocol compliance</li><li>No external binary needed — runs within the Actant process</li></ul><h2 id="core-data-flows" tabindex="-1">Core Data Flows <a class="header-anchor" href="#core-data-flows" aria-label="Permalink to &quot;Core Data Flows&quot;">​</a></h2><h3 id="agent-creation-flow" tabindex="-1">Agent Creation Flow <a class="header-anchor" href="#agent-creation-flow" aria-label="Permalink to &quot;Agent Creation Flow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-dark github-dark vp-code" tabindex="0"><code><span class="line"><span>CLI: actant agent create myagent -t template</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>RPC: agent.create { name, template }</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>AgentManager.createAgent()</span></span>
<span class="line"><span>  ├── TemplateRegistry.get(templateName)</span></span>
<span class="line"><span>  ├── AgentInitializer.initialize()</span></span>
<span class="line"><span>  │   ├── InitializationPipeline.execute()</span></span>
<span class="line"><span>  │   │   ├── MkdirStep (create instance dir)</span></span>
<span class="line"><span>  │   │   ├── FileCopyStep (copy initializer files)</span></span>
<span class="line"><span>  │   │   └── ExecStep (run init commands)</span></span>
<span class="line"><span>  │   └── ContextMaterializer.materialize()</span></span>
<span class="line"><span>  │       ├── WorkspaceBuilder.build(domainContext)</span></span>
<span class="line"><span>  │       │   ├── SkillsHandler → AGENTS.md / .claude/</span></span>
<span class="line"><span>  │       │   ├── PromptsHandler → prompts in workspace</span></span>
<span class="line"><span>  │       │   ├── McpServersHandler → .cursor/mcp.json</span></span>
<span class="line"><span>  │       │   └── WorkflowHandler → .trellis/workflow.md</span></span>
<span class="line"><span>  │       └── Write instance-meta.json</span></span>
<span class="line"><span>  └── Return AgentInstanceMeta</span></span></code></pre></div><h3 id="agent-run-flow-one-shot" tabindex="-1">Agent Run Flow (One-Shot) <a class="header-anchor" href="#agent-run-flow-one-shot" aria-label="Permalink to &quot;Agent Run Flow (One-Shot)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-dark github-dark vp-code" tabindex="0"><code><span class="line"><span>CLI: actant agent run myagent --prompt &quot;hello&quot;</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>RPC: agent.run { name, prompt }</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>AgentManager.runPrompt()</span></span>
<span class="line"><span>  ├── Ensure agent exists (or auto-create from template)</span></span>
<span class="line"><span>  ├── Determine launch mode: one-shot</span></span>
<span class="line"><span>  ├── Start agent if not running</span></span>
<span class="line"><span>  │   ├── BackendResolver.resolveAcpBackend() or resolveBackend()</span></span>
<span class="line"><span>  │   └── ProcessLauncher.launch() or AcpConnection.connect()</span></span>
<span class="line"><span>  ├── Communicator.runPrompt(prompt)</span></span>
<span class="line"><span>  │   ├── AcpCommunicator: session.create → session.prompt → session.close</span></span>
<span class="line"><span>  │   └── ClaudeCodeCommunicator: spawn claude -p --output-format json</span></span>
<span class="line"><span>  └── Return { text, sessionId }</span></span></code></pre></div><h3 id="agent-open-flow" tabindex="-1">Agent Open Flow <a class="header-anchor" href="#agent-open-flow" aria-label="Permalink to &quot;Agent Open Flow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-dark github-dark vp-code" tabindex="0"><code><span class="line"><span>CLI: actant agent open myagent</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>RPC: agent.open { name }</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>AgentManager.openAgent()</span></span>
<span class="line"><span>  ├── BackendResolver.openBackend(backendType, workspaceDir)</span></span>
<span class="line"><span>  │   ├── BackendManager.get(backendType)</span></span>
<span class="line"><span>  │   ├── getPlatformCommand(openCommand)</span></span>
<span class="line"><span>  │   └── Return { command, args, cwd?, openSpawnOptions }</span></span>
<span class="line"><span>  └── Return result to CLI</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>CLI: spawn(command, args, { cwd, ...openSpawnOptions, detached: true })</span></span></code></pre></div><h2 id="agent-lifecycle-state-machine" tabindex="-1">Agent Lifecycle State Machine <a class="header-anchor" href="#agent-lifecycle-state-machine" aria-label="Permalink to &quot;Agent Lifecycle State Machine&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-dark github-dark vp-code" tabindex="0"><code><span class="line"><span>                    ┌─────────┐</span></span>
<span class="line"><span>          create ──►│ created │</span></span>
<span class="line"><span>                    └────┬────┘</span></span>
<span class="line"><span>                         │ start</span></span>
<span class="line"><span>                    ┌────▼────┐</span></span>
<span class="line"><span>                    │starting │</span></span>
<span class="line"><span>                    └────┬────┘</span></span>
<span class="line"><span>              success ───┤      ├─── failure</span></span>
<span class="line"><span>                    ┌────▼────┐ │  ┌───────┐</span></span>
<span class="line"><span>                    │ running │ └─►│ error │</span></span>
<span class="line"><span>                    └────┬────┘    └───────┘</span></span>
<span class="line"><span>                         │ stop</span></span>
<span class="line"><span>                    ┌────▼────┐</span></span>
<span class="line"><span>                    │stopping │</span></span>
<span class="line"><span>                    └────┬────┘</span></span>
<span class="line"><span>                         │</span></span>
<span class="line"><span>                    ┌────▼────┐</span></span>
<span class="line"><span>          destroy ──│ stopped │</span></span>
<span class="line"><span>                    └─────────┘</span></span></code></pre></div><p><strong>Launch Modes and Exit Behavior:</strong></p><table tabindex="0"><thead><tr><th>Mode</th><th>On Process Exit</th><th>On Daemon Restart</th></tr></thead><tbody><tr><td><code>direct</code></td><td>→ stopped</td><td>→ stopped</td></tr><tr><td><code>acp-background</code></td><td>→ stopped</td><td>→ stopped</td></tr><tr><td><code>acp-service</code></td><td>→ restart (if under limit)</td><td>→ restart</td></tr><tr><td><code>one-shot</code></td><td>→ destroy (if autoDestroy)</td><td>→ stopped</td></tr></tbody></table><h2 id="configuration-hierarchy" tabindex="-1">Configuration Hierarchy <a class="header-anchor" href="#configuration-hierarchy" aria-label="Permalink to &quot;Configuration Hierarchy&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-dark github-dark vp-code" tabindex="0"><code><span class="line"><span>AgentTemplate</span></span>
<span class="line"><span>├── name, version, description</span></span>
<span class="line"><span>├── backend: { type, args?, env? }</span></span>
<span class="line"><span>├── provider: { type, protocol?, model?, apiKey? }</span></span>
<span class="line"><span>├── domainContext</span></span>
<span class="line"><span>│   ├── skills: string[]          → SkillDefinition[]</span></span>
<span class="line"><span>│   ├── prompts: string[]         → PromptDefinition[]</span></span>
<span class="line"><span>│   ├── mcpServers: McpServerRef[]</span></span>
<span class="line"><span>│   ├── subAgents: SubAgentRef[]</span></span>
<span class="line"><span>│   ├── workflows: string[]       → WorkflowDefinition[]</span></span>
<span class="line"><span>│   └── plugins: string[]         → PluginDefinition[]</span></span>
<span class="line"><span>├── permissions: { allow, deny, ask, defaultMode }</span></span>
<span class="line"><span>├── initializer: { steps[] }</span></span>
<span class="line"><span>├── schedule: { heartbeat?, cron?, hooks? }</span></span>
<span class="line"><span>└── metadata: Record&lt;string, string&gt;</span></span></code></pre></div><h2 id="built-in-resources" tabindex="-1">Built-in Resources <a class="header-anchor" href="#built-in-resources" aria-label="Permalink to &quot;Built-in Resources&quot;">​</a></h2><h3 id="backends-via-actant-hub-built-in" tabindex="-1">Backends (via actant-hub + built-in) <a class="header-anchor" href="#backends-via-actant-hub-built-in" aria-label="Permalink to &quot;Backends (via actant-hub + built-in)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Modes</th></tr></thead><tbody><tr><td>cursor</td><td>IDE</td><td>resolve, open</td></tr><tr><td>cursor-agent</td><td>TUI</td><td>resolve, open, acp</td></tr><tr><td>claude-code</td><td>CLI</td><td>resolve, open, acp</td></tr><tr><td>pi</td><td>In-process</td><td>acp</td></tr><tr><td>custom</td><td>User-defined</td><td>resolve</td></tr></tbody></table><h3 id="providers" tabindex="-1">Providers <a class="header-anchor" href="#providers" aria-label="Permalink to &quot;Providers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Name</th><th>Protocol</th></tr></thead><tbody><tr><td>anthropic</td><td>anthropic</td></tr><tr><td>openai</td><td>openai</td></tr><tr><td>gemini</td><td>openai</td></tr><tr><td>openrouter</td><td>openai</td></tr></tbody></table><h3 id="default-source-actant-hub" tabindex="-1">Default Source: actant-hub <a class="header-anchor" href="#default-source-actant-hub" aria-label="Permalink to &quot;Default Source: actant-hub&quot;">​</a></h3><ul><li>3 templates: code-reviewer, qa-engineer, doc-writer</li><li>3 skills: code-review, test-writer, doc-writer</li><li>2 prompts: code-assistant, qa-assistant</li><li>2 MCP servers: filesystem, memory-server</li><li>4 backends: cursor, cursor-agent, claude-code, pi</li><li>2 presets: web-dev, devops</li></ul><h2 id="current-version-status-v0-2-2" tabindex="-1">Current Version Status (v0.2.2) <a class="header-anchor" href="#current-version-status-v0-2-2" aria-label="Permalink to &quot;Current Version Status (v0.2.2)&quot;">​</a></h2><h3 id="completed-phase-1-2" tabindex="-1">Completed (Phase 1-2) <a class="header-anchor" href="#completed-phase-1-2" aria-label="Permalink to &quot;Completed (Phase 1-2)&quot;">​</a></h3><ul><li>Full agent lifecycle (create, start, stop, destroy, attach, detach)</li><li>Multi-backend support (Cursor, Claude Code, Pi, custom)</li><li>ACP protocol integration</li><li>Domain component system (6 types, CRUD, import/export)</li><li>Source system with actant-hub</li><li>Template/preset system</li><li>Scheduler (heartbeat, cron, hooks)</li><li>Session lease system</li><li>Permission system</li><li>CLI with 68 subcommands</li><li>Daemon with 62 RPC methods</li><li>Backend as VersionedComponent (BackendManager)</li><li>Backend availability checking + install methods</li><li><code>agent run</code> headless mode (windowsHide)</li><li><code>agent open</code> with backend-specific spawn config</li><li><code>agent destroy --force</code> idempotent behavior</li></ul><h3 id="in-progress-phase-3" tabindex="-1">In Progress (Phase 3) <a class="header-anchor" href="#in-progress-phase-3" aria-label="Permalink to &quot;In Progress (Phase 3)&quot;">​</a></h3><ul><li>Frontend dashboard (planned)</li><li>Plugin execution engine</li><li>Advanced scheduling (cross-agent dependencies)</li></ul><h3 id="known-limitations" tabindex="-1">Known Limitations <a class="header-anchor" href="#known-limitations" aria-label="Permalink to &quot;Known Limitations&quot;">​</a></h3><ul><li><code>gateway.lease</code> RPC defined but not implemented (#117)</li><li>MCP server package is a stub</li><li>No Linux/macOS installation script yet</li><li>Backend <code>existenceCheck</code> requires the binary to be in PATH</li></ul><hr><p>详细版本快照见仓库中 <code>docs/stage/v0.2.2/architecture.md</code>。</p>`,88)])])}const g=a(o,[["render",r]]);export{u as __pageData,g as default};
